import android.content.Context
import android.content.SharedPreferences
import android.util.Log
import java.io.*


class AuthenticationManager(context: Context) {
    private val sharedPreferences = context.getSharedPreferences("auth", Context.MODE_PRIVATE)

    fun saveAuthToken(token: String, userId: Int): Boolean {
        return sharedPreferences
            .edit()
            .putString("token", token)
            .putInt("userId", userId)
            .commit()
    }

    fun getAuthToken(): String? = sharedPreferences.getString("token", null)

    fun getUserId(): Int? = sharedPreferences.getInt("userId", -1)
}